// Runes store for LOCALLY-GENERATED session titles. Each agent card's title is a
// short focus description ("SKIPA-45: Fix Feature", "Improve frontend dialog
// handling") generated by the on-device model from the USER's messages in that
// session's transcript — re-derived only when the user's messages actually change.
//
// The Rust `session_focus(sessionId, cwd, cloudFallback)` command does the model call
// (extract the user's messages → ask the local `llama-server` polish model; and, when
// the opt-in `titles.cloudFallback` setting is on, fall back to `claude -p` Haiku if the
// on-device model is unavailable). It's gated entirely on the
// transcript's `user_hash` (from the activity store): a title is (re)requested
// only when that hash differs from the one we already titled, and at most once per
// throttle window per pane, so an active session never spams the model.

import { invoke } from '@tauri-apps/api/core';
import type { PaneRef } from './activity.svelte';
import { titleSettings } from '$lib/settings/titles.svelte';

/**
 * Min interval between title requests for one pane (ms) — a small FLOOR, not a
 * long cool-down. The title is gated on the transcript's user-message hash, so a
 * NEW user message (changed hash) must re-derive the title PROMPTLY rather than
 * waiting out a long window. We keep only a few-seconds floor to coalesce a rapid
 * burst of polls / messages into one request and avoid re-deriving mid-stream;
 * 3 s is short enough to feel immediate after a message yet long enough to
 * absorb the ~per-second activity poll and back-to-back edits. (Was 120_000 — a
 * 2-minute window that wrongly blocked refreshing the title for up to 2 min after
 * the user had already sent a new message.)
 */
export const TITLE_THROTTLE_MS = 3_000;

/** localStorage key for the persisted, sessionId-keyed title cache. */
const STORAGE_KEY = 'agent-desktop:session-titles';

/** A pane's cached title + the user-hash it was generated for. */
export interface TitleEntry {
  title: string | null;
  hash: string | null;
  /**
   * Set when the user gave this session a CUSTOM title (header inline-edit or the
   * agent card's "Rename" menu). A manual title is STICKY: it displays in place of
   * any auto-generated title and `shouldRequest` returns false for it forever, so
   * later messages never re-generate it. Persisted (under sessionId) so it survives
   * restart/resume. Absent/false for auto-generated titles.
   */
  manual?: boolean;
}

/** Load the persisted sessionId -> entry cache (survives restart / resume). */
function loadPersisted(): Record<string, TitleEntry> {
  if (typeof localStorage === 'undefined') return {};
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return {};
    const parsed = JSON.parse(raw) as Record<string, TitleEntry>;
    return parsed && typeof parsed === 'object' ? parsed : {};
  } catch {
    return {};
  }
}

/**
 * PURE: whether to (re)request a title for a pane. Requests when the user has
 * messages (`userHash` is set) and the current title is for a DIFFERENT hash, we
 * are not already fetching that same hash, and the throttle window has elapsed.
 * A MANUAL (custom) title is sticky — auto-generation stops for it permanently.
 */
export function shouldRequest(
  entry: TitleEntry | undefined,
  pendingHash: string | undefined,
  userHash: string | null,
  lastAttempt: number,
  nowMs: number,
  throttleMs: number = TITLE_THROTTLE_MS
): boolean {
  if (entry?.manual) return false; // custom title — never auto-regenerate it
  if (!userHash) return false;
  if (entry?.hash === userHash) return false; // already titled for this hash
  if (pendingHash === userHash) return false; // already fetching this hash
  if (nowMs - lastAttempt < throttleMs) return false; // throttle
  return true;
}

/** Reactive title store: paneId -> {title, hash}. */
export class TitleStore {
  byPane = $state<Record<string, TitleEntry>>({});
  // The DURABLE cache, keyed by sessionId (stable across restart/resume). The
  // paneId-keyed `byPane` is hydrated from here on `refresh` so a restored agent
  // shows its last title immediately, with no model call.
  #bySession: Record<string, TitleEntry> = loadPersisted();
  #pending = new Map<string, string>();
  #lastAttempt = new Map<string, number>();

  /** The generated title for a pane, or null when none yet. */
  titleFor(paneId: string): string | null {
    return this.byPane[paneId]?.title ?? null;
  }

  /**
   * Set a user-chosen CUSTOM title for a session (header inline-edit or the agent
   * card's "Rename" menu). Updates the runtime `byPane` cache so it shows at once,
   * marks the entry `manual` so `shouldRequest` never re-generates it, and PERSISTS
   * it under `sessionId` (durable, survives restart/resume — it's reloaded into
   * `byPane` by `hydrate`). An empty/whitespace title is ignored (no-op): a custom
   * title can never blank out the displayed name.
   */
  setManualTitle(paneId: string, sessionId: string | null, title: string): void {
    const trimmed = title.trim();
    if (!trimmed) return; // ignore empty — never clear the shown title
    // A manual title is hash-independent (it never re-generates), so we don't pin
    // it to a userHash; `manual` is the sole gate `shouldRequest` reads.
    const entry: TitleEntry = { title: trimmed, hash: null, manual: true };
    this.byPane[paneId] = entry;
    if (sessionId) {
      this.#bySession[sessionId] = entry;
      this.#persist();
    }
  }

  /**
   * Seed runtime titles from the durable, sessionId-keyed cache for any pane that
   * isn't titled yet. PURE cache read — no model call, no userHash needed — so a
   * restored agent renders its previous title IMMEDIATELY on mount, before the
   * first (async) activity poll runs. Without this, `titleFor` returns null until
   * the poll completes and the card falls back to its "Session N" name for a beat.
   * Idempotent and called both on mount and at the top of every `refresh`.
   */
  hydrate(panes: PaneRef[]): void {
    for (const p of panes) {
      if (!this.byPane[p.paneId] && p.sessionId) {
        const saved = this.#bySession[p.sessionId];
        if (saved) this.byPane[p.paneId] = saved;
      }
    }
  }

  /**
   * For each pane, request a fresh session title when the user's messages changed
   * (per `hashOf(paneId)`), subject to the per-pane throttle. Fire-and-forget; the
   * store updates reactively when each title resolves.
   */
  refresh(panes: PaneRef[], hashOf: (paneId: string) => string | null | undefined, nowMs: number): void {
    // Seed from the durable cache first so a restored agent shows its previous
    // title at once (and we skip the model call when its messages are unchanged).
    this.hydrate(panes);
    for (const p of panes) {
      const userHash = hashOf(p.paneId) ?? null;
      const entry = this.byPane[p.paneId];
      const pending = this.#pending.get(p.paneId);
      const last = this.#lastAttempt.get(p.paneId) ?? 0;
      if (!shouldRequest(entry, pending, userHash, last, nowMs)) continue;
      this.#pending.set(p.paneId, userHash as string);
      this.#lastAttempt.set(p.paneId, nowMs);
      void this.#fetch(p, userHash as string);
    }
  }

  async #fetch(pane: PaneRef, hash: string): Promise<void> {
    try {
      const title = await invoke<string | null>('session_focus', {
        sessionId: pane.sessionId,
        cwd: pane.cwd,
        // Opt-in: allow the backend to fall back to `claude -p` (Haiku) when the
        // on-device title model is unavailable. Off by default (on-device only).
        cloudFallback: titleSettings.prefs.cloudFallback
      });
      // Bail if the user gave this session a CUSTOM title while we were awaiting:
      // a manual title is sticky and must NEVER be clobbered by a now-stale
      // auto-generation that was already in flight when the rename happened.
      if (this.byPane[pane.paneId]?.manual) return;
      if (pane.sessionId && this.#bySession[pane.sessionId]?.manual) return;
      const next: TitleEntry = { title: title ?? null, hash };
      this.byPane[pane.paneId] = next;
      // Persist a resolved title under its sessionId so it survives a restart.
      if (pane.sessionId && next.title) {
        this.#bySession[pane.sessionId] = next;
        this.#persist();
      }
    } catch (err) {
      console.warn('session_focus failed; keeping previous title:', err);
    } finally {
      if (this.#pending.get(pane.paneId) === hash) this.#pending.delete(pane.paneId);
    }
  }

  /** Write the durable sessionId-keyed cache to localStorage (best-effort). */
  #persist(): void {
    if (typeof localStorage === 'undefined') return;
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(this.#bySession));
    } catch {
      /* ignore quota / disabled storage */
    }
  }
}

/** Singleton, imported by the route + the overview card. */
export const titles = new TitleStore();
